<template><view class="page"><view class="row"><view class="title">提醒管理</view><button class="btn" @click="create">新增</button></view><EmptyState v-if="!items.length"/><AppCard v-for="x in items" :key="x.id" :title="x.title"><view>{{x.content}}</view><view class="subtitle">{{x.timeOfDay}} · {{x.repeatRule}}</view><button class="btn secondary" @click="remove(x.id)">删除</button></AppCard></view></template><script setup lang="ts">import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import AppCard from'@/components/AppCard.vue';import EmptyState from'@/components/EmptyState.vue';import{qingxierApi}from'@/services/api';import{useDeviceStore}from'@/stores/device';const items=ref<any[]>([]),devices=useDeviceStore();async function load(){items.value=await qingxierApi.reminders()}onShow(load);async function create(){await devices.load();await qingxierApi.createReminder({deviceId:devices.currentId,type:'custom',title:'喝水',content:'阿西提醒你喝水啦',timeOfDay:'15:30',repeatRule:'FREQ=DAILY',needConfirm:true});await load()}async function remove(id:string){await qingxierApi.deleteReminder(id);await load()}</script>
